import React from 'react';
import { Link } from 'react-router-dom';
import { AppBar, Toolbar, Button, Box } from '@mui/material';

const Navbar = () => {
  const handleDownloadClick = () => {
    window.open('https://huggingface.co/hyonbokan/BGPStream13-10k-cutoff-1024-max-2048', '_blank');
  };

  const linkStyle = (theme) => ({
    color: 'inherit',
    textDecoration: 'none',
    padding: theme.spacing(1, 2), // Use theme's spacing for consistency
    borderRadius: theme.shape.borderRadius, // Apply border radius from theme
    margin: '0',
    '&:hover': {
      textDecoration: 'underline', // This should give us an underline on hover
      backgroundColor: theme.palette.action.hover, // Use theme's hover color
    },
    '&:not(:last-child)': {
      marginRight: theme.spacing(2), // Add horizontal margin from theme's spacing
    }
  });

  return (
    <AppBar position="static" sx={{ backgroundColor: '#2D3748', color: 'white' }}>
      <Toolbar sx={{ justifyContent: 'flex-start' }}>
        <Box sx={{ display: 'flex', alignItems: 'left', marginRight: 'auto' }}>
          <Link to="/" sx={linkStyle}>Home</Link>
        </Box>
        <Box sx={{ display: 'flex', alignItems: 'left', marginRight: 'auto' }}>
          <Link to="/dataset" sx={linkStyle}>Dataset</Link>
        </Box>
        <Box sx={{ display: 'flex', alignItems: 'left', marginRight: 'auto' }}>
          <Link to="/bgp_llama" sx={linkStyle}>BGP-LLaMA</Link>
        </Box>
        <Button color="primary" variant="contained" onClick={handleDownloadClick}>
          Download models
        </Button>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
